   hostPath: string;
   containerPath: string;
   readOnly: boolean;
+  hostMountPrefixMap?: Record<string, string>;
 }): string {
-  return `${params.hostPath}:${params.containerPath}:${params.readOnly ? "ro,z" : "z"}`;
